import { useState, useEffect, useRef } from "react"

const CYAN = "#00f5ff"
const GREEN = "#22c55e"

function CameraFeed({ label, coords, type }) {
  const canvasRef = useRef(null)
  const animRef = useRef(null)

  useEffect(() => {
    const canvas = canvasRef.current
    if (!canvas) return
    const ctx = canvas.getContext("2d")
    let frame = 0

    function draw() {
      const w = canvas.width
      const h = canvas.height
      ctx.fillStyle = "#000"
      ctx.fillRect(0, 0, w, h)

      if (type === "skyline") {
        // Chicago skyline silhouette
        ctx.fillStyle = "#111118"
        ctx.fillRect(0, 0, w, h)
        // Buildings
        const buildings = [
          [0, 0.6, 0.08, 0.4], [0.05, 0.5, 0.06, 0.5], [0.1, 0.55, 0.05, 0.45],
          [0.14, 0.4, 0.04, 0.6], [0.17, 0.45, 0.06, 0.55], [0.22, 0.35, 0.05, 0.65],
          [0.26, 0.5, 0.07, 0.5], [0.32, 0.42, 0.04, 0.58], [0.35, 0.38, 0.06, 0.62],
          [0.4, 0.55, 0.05, 0.45], [0.44, 0.48, 0.08, 0.52], [0.51, 0.3, 0.05, 0.7],
          [0.55, 0.45, 0.06, 0.55], [0.6, 0.52, 0.07, 0.48], [0.66, 0.44, 0.05, 0.56],
          [0.7, 0.58, 0.06, 0.42], [0.75, 0.46, 0.08, 0.54], [0.82, 0.5, 0.05, 0.5],
          [0.86, 0.42, 0.06, 0.58], [0.91, 0.55, 0.09, 0.45]
        ]
        buildings.forEach(([x, y, bw, bh]) => {
          const flicker = Math.random() > 0.98
          ctx.fillStyle = flicker ? "#2a2a4e" : "#1a1a3a"
          ctx.fillRect(x * w, y * h, bw * w, bh * h)
          // Windows
          for (let wy = y * h + 4; wy < h - 4; wy += 6) {
            for (let wx = x * w + 2; wx < (x + bw) * w - 2; wx += 5) {
              if (Math.random() > 0.6) {
                ctx.fillStyle = Math.random() > 0.7 ? "#00f5ff44" : "#22c55e33"
                ctx.fillRect(wx, wy, 3, 3)
              }
            }
          }
        })
        // Lake
        ctx.fillStyle = "#050510"
        ctx.fillRect(0, 0.75 * h, w, 0.25 * h)
        // Reflection
        const gradient = ctx.createLinearGradient(0, 0.75 * h, 0, h)
        gradient.addColorStop(0, "rgba(0,245,255,0.05)")
        gradient.addColorStop(1, "rgba(0,0,0,0)")
        ctx.fillStyle = gradient
        ctx.fillRect(0, 0.75 * h, w, 0.25 * h)
      }

      if (type === "street") {
        // Street perspective
        ctx.fillStyle = "#0d0d14"
        ctx.fillRect(0, 0, w, h)
        // Road
        ctx.fillStyle = "#0a0a0f"
        ctx.beginPath()
        ctx.moveTo(w * 0.3, h)
        ctx.lineTo(w * 0.7, h)
        ctx.lineTo(w * 0.52, h * 0.45)
        ctx.lineTo(w * 0.48, h * 0.45)
        ctx.fill()
        // Road markings
        for (let i = 0; i < 5; i++) {
          const y = h * (0.5 + i * 0.1)
          const xw = (y / h - 0.45) * w * 0.5
          ctx.strokeStyle = `rgba(34,197,94,${0.1 + i * 0.05})`
          ctx.lineWidth = 1
          ctx.beginPath()
          ctx.moveTo(w * 0.5 - xw * 0.1, y)
          ctx.lineTo(w * 0.5 + xw * 0.1, y)
          ctx.stroke()
        }
        // Buildings sides
        ctx.fillStyle = "#111120"
        ctx.fillRect(0, 0, w * 0.32, h)
        ctx.fillRect(w * 0.68, 0, w * 0.32, h)
        // Windows on buildings
        for (let wy = 10; wy < h - 10; wy += 15) {
          for (let side = 0; side < 2; side++) {
            const startX = side === 0 ? 5 : w * 0.72
            const endX = side === 0 ? w * 0.28 : w - 5
            for (let wx = startX; wx < endX; wx += 12) {
              if (Math.random() > 0.7) {
                ctx.fillStyle = `rgba(0,245,255,${Math.random() * 0.2})`
                ctx.fillRect(wx, wy, 6, 8)
              }
            }
          }
        }
        // Moving figure (Hybrid)
        const figX = w * 0.48 + Math.sin(frame * 0.02) * w * 0.03
        const figY = h * 0.55 + Math.cos(frame * 0.015) * h * 0.02
        ctx.fillStyle = `rgba(239,68,68,${0.7 + Math.sin(frame * 0.1) * 0.2})`
        ctx.beginPath()
        ctx.ellipse(figX, figY, 3, 6, 0, 0, Math.PI * 2)
        ctx.fill()
        // Target reticle
        ctx.strokeStyle = "rgba(239,68,68,0.8)"
        ctx.lineWidth = 0.5
        ctx.beginPath()
        ctx.arc(figX, figY, 10, 0, Math.PI * 2)
        ctx.stroke()
        ctx.beginPath()
        ctx.moveTo(figX - 14, figY)
        ctx.lineTo(figX - 8, figY)
        ctx.moveTo(figX + 8, figY)
        ctx.lineTo(figX + 14, figY)
        ctx.moveTo(figX, figY - 14)
        ctx.lineTo(figX, figY - 8)
        ctx.moveTo(figX, figY + 8)
        ctx.lineTo(figX, figY + 14)
        ctx.stroke()
      }

      if (type === "map") {
        // Sector map
        ctx.fillStyle = "#020408"
        ctx.fillRect(0, 0, w, h)
        // Grid
        ctx.strokeStyle = "rgba(0,245,255,0.08)"
        ctx.lineWidth = 0.5
        for (let x = 0; x < w; x += 20) {
          ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, h); ctx.stroke()
        }
        for (let y = 0; y < h; y += 20) {
          ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(w, y); ctx.stroke()
        }
        // Lake Michigan
        ctx.fillStyle = "rgba(0,245,255,0.05)"
        ctx.fillRect(w * 0.72, 0, w * 0.28, h)
        ctx.strokeStyle = "rgba(0,245,255,0.15)"
        ctx.lineWidth = 1
        ctx.beginPath()
        ctx.moveTo(w * 0.72, 0); ctx.lineTo(w * 0.72, h); ctx.stroke()
        // Streets
        const streets = [
          [0, 0.25, 0.72, 0.25], [0, 0.5, 0.72, 0.5], [0, 0.75, 0.72, 0.75],
          [0.18, 0, 0.18, 1], [0.36, 0, 0.36, 1], [0.54, 0, 0.54, 1]
        ]
        ctx.strokeStyle = "rgba(34,197,94,0.12)"
        ctx.lineWidth = 1
        streets.forEach(([x1, y1, x2, y2]) => {
          ctx.beginPath()
          ctx.moveTo(x1 * w, y1 * h)
          ctx.lineTo(x2 * w, y2 * h)
          ctx.stroke()
        })
        // Hybrid clusters
        const clusters = [
          { x: 0.22, y: 0.3, r: 8, level: 4 },
          { x: 0.45, y: 0.6, r: 12, level: 3 },
          { x: 0.15, y: 0.7, r: 6, level: 4 },
          { x: 0.6, y: 0.35, r: 15, level: 2 },
        ]
        clusters.forEach(({ x, y, r, level }) => {
          const pulse = Math.sin(frame * 0.05 + x * 10) * 0.3
          const color = level === 4 ? "255,165,0" : level === 3 ? "239,68,68" : "147,51,234"
          ctx.strokeStyle = `rgba(${color},${0.4 + pulse})`
          ctx.lineWidth = 1
          ctx.beginPath()
          ctx.arc(x * w, y * h, r + pulse * 3, 0, Math.PI * 2)
          ctx.stroke()
          ctx.fillStyle = `rgba(${color},0.6)`
          ctx.beginPath()
          ctx.arc(x * w, y * h, 2, 0, Math.PI * 2)
          ctx.fill()
          ctx.fillStyle = `rgba(${color},0.8)`
          ctx.font = "7px monospace"
          ctx.fillText(`L${level}`, x * w + 5, y * h - 4)
        })
        // C.L.A.W. signal direction
        const signalAngle = -0.8 + Math.sin(frame * 0.02) * 0.05
        ctx.strokeStyle = `rgba(255,0,170,${0.3 + Math.sin(frame * 0.05) * 0.2})`
        ctx.lineWidth = 1
        ctx.setLineDash([3, 3])
        ctx.beginPath()
        ctx.moveTo(w * 0.36, h * 0.5)
        ctx.lineTo(w * 0.36 + Math.cos(signalAngle) * 60, h * 0.5 + Math.sin(signalAngle) * 60)
        ctx.stroke()
        ctx.setLineDash([])
        ctx.fillStyle = "rgba(255,0,170,0.6)"
        ctx.font = "6px monospace"
        ctx.fillText("C.L.A.W.", w * 0.36 + Math.cos(signalAngle) * 65, h * 0.5 + Math.sin(signalAngle) * 65)
      }

      // Scanlines
      for (let y = 0; y < h; y += 3) {
        ctx.fillStyle = "rgba(0,0,0,0.15)"
        ctx.fillRect(0, y, w, 1)
      }

      // Random noise
      if (Math.random() > 0.97) {
        ctx.fillStyle = `rgba(0,245,255,${Math.random() * 0.05})`
        ctx.fillRect(0, Math.random() * h, w, Math.random() * 3)
      }

      // Vignette
      const vignette = ctx.createRadialGradient(w/2, h/2, h*0.3, w/2, h/2, h*0.8)
      vignette.addColorStop(0, "rgba(0,0,0,0)")
      vignette.addColorStop(1, "rgba(0,0,0,0.6)")
      ctx.fillStyle = vignette
      ctx.fillRect(0, 0, w, h)

      // Timestamp
      const now = new Date()
      const ts = `2162.${String(now.getMonth()+1).padStart(2,'0')}.${String(now.getDate()).padStart(2,'0')} ${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}:${String(now.getSeconds()).padStart(2,'0')}`
      ctx.fillStyle = "rgba(34,197,94,0.7)"
      ctx.font = "8px monospace"
      ctx.fillText(ts, 4, h - 4)

      // REC indicator
      if (Math.floor(frame / 30) % 2 === 0) {
        ctx.fillStyle = "rgba(239,68,68,0.8)"
        ctx.beginPath()
        ctx.arc(w - 10, 8, 3, 0, Math.PI * 2)
        ctx.fill()
        ctx.fillStyle = "rgba(239,68,68,0.8)"
        ctx.font = "7px monospace"
        ctx.fillText("REC", w - 28, 12)
      }

      frame++
      animRef.current = requestAnimationFrame(draw)
    }

    draw()
    return () => cancelAnimationFrame(animRef.current)
  }, [type])

  return (
    <div style={{ position: "relative" }}>
      <canvas
        ref={canvasRef}
        width={220}
        height={130}
        style={{ display: "block", border: "1px solid rgba(0,245,255,0.1)" }}
      />
      <div style={{
        position: "absolute", top: 4, left: 4,
        fontSize: 7, color: "rgba(0,245,255,0.7)",
        fontFamily: "monospace", letterSpacing: 1,
        textShadow: "0 0 4px rgba(0,245,255,0.5)"
      }}>{label}</div>
      <div style={{
        position: "absolute", bottom: 4, right: 4,
        fontSize: 7, color: "rgba(0,245,255,0.5)",
        fontFamily: "monospace"
      }}>{coords}</div>
    </div>
  )
}

export default function LiveFeed({ onBack }) {
  const [lines, setLines] = useState([])
  const [isLoading, setIsLoading] = useState(false)
  const [glitch, setGlitch] = useState(false)
  const [staticEffect, setStaticEffect] = useState(false)
  const [lastUpdate, setLastUpdate] = useState(null)
  const [signalStrength, setSignalStrength] = useState(87)
  const feedRef = useRef(null)

  useEffect(() => {
    const glitchInterval = setInterval(() => {
      setGlitch(true)
      setTimeout(() => setGlitch(false), 100)
    }, 5000)
    const signalInterval = setInterval(() => {
      setSignalStrength(prev => {
        const delta = (Math.random() - 0.5) * 6
        return Math.min(99, Math.max(60, Math.round(prev + delta)))
      })
    }, 2000)
    generateFeed()
    return () => {
      clearInterval(glitchInterval)
      clearInterval(signalInterval)
    }
  }, [])

  useEffect(() => {
    if (feedRef.current) {
      feedRef.current.scrollTop = feedRef.current.scrollHeight
    }
  }, [lines])

  async function generateFeed() {
    setIsLoading(true)
    setStaticEffect(true)
    setTimeout(() => setStaticEffect(false), 800)

    try {
      const response = await fetch("https://etf-api-production-093e.up.railway.app/signal-feed", {
        method: "POST",
        headers: { "Content-Type": "application/json" }
      })
      const data = await response.json()
      const text = data.text || "TRANSMISSION ERROR — SIGNAL LOST"

      const timestamp = new Date().toISOString().replace("T", " ").substring(0, 19) + " UTC"
      setLastUpdate(timestamp)

      const newLines = text.split("\n").filter(l => l.trim())
      setLines([])

      for (let i = 0; i < newLines.length; i++) {
        await new Promise(r => setTimeout(r, 80))
        setLines(prev => [...prev, newLines[i]])
      }
    } catch (e) {
      setLines(["TRANSMISSION ERROR — SIGNAL LOST", "RETRYING CONNECTION..."])
    }
    setIsLoading(false)
  }

  const getLineColor = (line) => {
    if (line.includes("CRITICAL")) return "#ef4444"
    if (line.includes("HIGH")) return "#f97316"
    if (line.includes("MODERATE")) return "#f59e0b"
    if (line.includes("LOW")) return GREEN
    if (line.startsWith("##") || line.startsWith("#")) return CYAN
    if (line.includes("VOSS") || line.includes("C.L.A.W.")) return "#ff00aa"
    if (line.match(/^\[/)) return "#9ca3af"
    return "#9ca3af"
  }

  return (
    <div style={{ maxWidth: 760, margin: "0 auto", padding: "20px" }}>
      <div onClick={onBack} style={{ fontSize: 11, color: CYAN, cursor: "pointer", marginBottom: 16, letterSpacing: 2 }}>
        ← BACK TO ARCHIVE
      </div>

      {/* Camera feeds row */}
      <div style={{ display: "flex", gap: 6, marginBottom: 8, overflowX: "auto" }}>
        <CameraFeed label="CAM-01 / LOOP NORTH" coords="41.8827°N 87.6233°W" type="skyline" />
        <CameraFeed label="CAM-07 / MICHIGAN AVE" coords="41.8796°N 87.6237°W" type="street" />
        <CameraFeed label="SECTOR MAP / INNER-01-04" coords="CLASSIFIED" type="map" />
      </div>

      {/* TV Frame */}
      <div style={{
        background: "#000",
        border: `2px solid rgba(0,245,255,0.3)`,
        borderRadius: 4,
        overflow: "hidden",
        boxShadow: `0 0 40px rgba(0,245,255,0.1)`,
        filter: glitch ? "hue-rotate(180deg) brightness(1.5)" : "none",
        transition: "filter 0.05s"
      }}>
        <div style={{
          background: "rgba(0,245,255,0.06)",
          borderBottom: `1px solid rgba(0,245,255,0.15)`,
          padding: "8px 14px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between"
        }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div style={{
              width: 8, height: 8, borderRadius: "50%",
              background: isLoading ? "#f59e0b" : GREEN,
              boxShadow: `0 0 8px ${isLoading ? "#f59e0b" : GREEN}`,
              animation: "pulse 1s infinite"
            }} />
            <span style={{ fontSize: 10, color: GREEN, letterSpacing: 3, fontFamily: "monospace" }}>
              {isLoading ? "RECEIVING..." : "● LIVE"}
            </span>
          </div>
          <span style={{ fontSize: 10, color: CYAN, letterSpacing: 2, fontFamily: "monospace" }}>
            INNER SECTORS DISPATCH — CHICAGO 2162
          </span>
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <span style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>SIG</span>
            <div style={{ width: 40, height: 4, background: "rgba(0,245,255,0.1)", borderRadius: 2 }}>
              <div style={{ width: `${signalStrength}%`, height: "100%", background: signalStrength > 70 ? GREEN : "#f59e0b", borderRadius: 2, transition: "width 0.5s" }} />
            </div>
            <span style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>{signalStrength}%</span>
          </div>
        </div>

        <div style={{ position: "relative", minHeight: 400 }}>
          <div style={{
            position: "absolute", inset: 0,
            background: "repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.15) 2px, rgba(0,0,0,0.15) 4px)",
            pointerEvents: "none", zIndex: 10
          }} />
          {staticEffect && (
            <div style={{
              position: "absolute", inset: 0, zIndex: 20,
              background: "repeating-linear-gradient(0deg, rgba(0,245,255,0.03) 0px, transparent 1px)"
            }} />
          )}
          <div
            ref={feedRef}
            style={{
              padding: "16px 14px",
              fontFamily: "monospace",
              fontSize: 12,
              lineHeight: 1.7,
              minHeight: 400,
              maxHeight: 500,
              overflowY: "auto",
              position: "relative",
              zIndex: 5
            }}
          >
            {lines.length === 0 && isLoading && (
              <div style={{ color: GREEN, letterSpacing: 2, fontSize: 11 }}>
                ESTABLISHING CONNECTION TO INNER SECTORS RELAY...
              </div>
            )}
            {lines.map((line, i) => (
              <div key={i} style={{
                color: getLineColor(line),
                marginBottom: line === "" ? 8 : 2,
                fontWeight: line.startsWith("#") || line.includes("CRITICAL") ? "bold" : "normal"
              }}>
                {line || "\u00A0"}
              </div>
            ))}
            {isLoading && lines.length > 0 && (
              <span style={{ color: GREEN, animation: "blink 0.5s infinite" }}>▊</span>
            )}
          </div>
        </div>

        <div style={{
          background: "rgba(0,245,255,0.04)",
          borderTop: `1px solid rgba(0,245,255,0.1)`,
          padding: "8px 14px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between"
        }}>
          <span style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>
            {lastUpdate ? `LAST UPDATE: ${lastUpdate}` : "AWAITING TRANSMISSION"}
          </span>
          <button
            onClick={generateFeed}
            disabled={isLoading}
            style={{
              background: isLoading ? "rgba(0,245,255,0.05)" : "rgba(0,245,255,0.1)",
              border: `1px solid rgba(0,245,255,${isLoading ? "0.1" : "0.3"})`,
              color: isLoading ? "#405060" : CYAN,
              padding: "4px 12px",
              fontSize: 9,
              letterSpacing: 2,
              cursor: isLoading ? "default" : "pointer",
              fontFamily: "monospace"
            }}
          >
            {isLoading ? "RECEIVING..." : "↺ REFRESH"}
          </button>
        </div>
      </div>

      <div style={{ marginTop: 12, fontSize: 10, color: "#405060", textAlign: "center", letterSpacing: 1 }}>
        SIGNAL.tv — LIVE TRANSMISSION FROM CHICAGO 2162 — CLASSIFIED FEED
      </div>

      <style>{`
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.3} }
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0} }
      `}</style>
    </div>
  )
}
